Create a function that finds how many prime numbers there are, up to the given integer.

Examples
primeNumbers(10) ➞ 4
// 2, 3, 5 and 7

primeNumbers(20) ➞ 8
// 2, 3, 5, 7, 11, 13, 17 and 19

primeNumbers(30) ➞ 10
// 2, 3, 5, 7, 11, 13, 17, 19, 23 and 29      solve in javascript

function primeNumbers(num) {
  let count = 0;

  for(let i = 2; i <= num; i++) {
    let isPrime = true;

    for(let j = 2; j < i; j++) {
      if(i % j === 0) {
        isPrime = false;
        break;
      }
    }

    if(isPrime) {
      count++;
    }
  }

  return count;
}

console.log(primeNumbers(10)); // 4
console.log(primeNumbers(20)); // 8
console.log(primeNumbers(30)); // 10

function primeInRange(n1, n2) {
  for(let i = n1; i <= n2; i++) {
    let isPrime = true;

    for(let j = 2; j < i; j++) {
      if(i % j === 0) {
        isPrime = false;
        break;
      }
    }

    if(isPrime) {
      return true;
    }
  }

  return false;
}

console.log(primeInRange(10, 15)); // true
console.log(primeInRange(62, 66)); // false
console.log(primeInRange(3, 5)); // true

Create a function that returns the frequency distribution of an array. This function should return an object, where the keys are the unique elements and the values are the frequency in which those elements occur.

Examples
getFrequencies(["A", "B", "A", "A", "A"]) ➞ { A: 4, B: 1 }

getFrequencies([1, 2, 3, 3, 2]) ➞ { "1": 1, "2": 2, "3": 2 }

getFrequencies([true, false, true, false, false]) ➞ { true: 2, false: 3 }

getFrequencies([]) ➞ {}
Notes
If given an empty array, return an empty object (see example #4).
The object should be in the same order as in the input array.    solve in javascript

function getFrequencies(arr) {
  let frequencies = {};

  for(let i = 0; i < arr.length; i++) {
    let element = arr[i];

    if(frequencies[element]) {
      frequencies[element]++;
    } else {
      frequencies[element] = 1;
    }
  }

  return frequencies;
}

console.log(getFrequencies(["A", "B", "A", "A", "A"]));
// { A: 4, B: 1 }

console.log(getFrequencies([1, 2, 3, 3, 2]));
// { "1": 1, "2": 2, "3": 2 }

console.log(getFrequencies([true, false, true, false, false]));
// { true: 2, false: 3 }

console.log(getFrequencies([]));
// {}

Create a function that takes an array of numbers and return "Boom!" if the digit 7 appears in the array. Otherwise, return "there is no 7 in the array".

Examples
sevenBoom([1, 2, 3, 4, 5, 6, 7]) ➞ "Boom!"
// 7 contains the number seven.

sevenBoom([8, 6, 33, 100]) ➞ "there is no 7 in the array"
// None of the items contain 7 within them.

sevenBoom([2, 55, 60, 97, 86]) ➞ "Boom!"
// 97 contains the number seven.   solve in javascript

function sevenBoom(arr) {
  for(let i = 0; i < arr.length; i++) {
    let number = arr[i].toString();

    if(number.includes("7")) {
      return "Boom!";
    }
  }

  return "there is no 7 in the array";
}

console.log(sevenBoom([1, 2, 3, 4, 5, 6, 7])); // "Boom!"
console.log(sevenBoom([8, 6, 33, 100])); // "there is no 7 in the array"
console.log(sevenBoom([2, 55, 60, 97, 86])); // "Boom!"

function jazzify(arr) {
  let jazzified = [];

  for(let i = 0; i < arr.length; i++) {
    let chord = arr[i];

    if(chord.charAt(chord.length - 1) !== "7") {
      jazzified.push(chord + "7");
    } else {
      jazzified.push(chord);
    }
  }

  return jazzified;
}

console.log(jazzify(["G", "F", "C"])); // ["G7", "F7", "C7"]
console.log(jazzify(["Dm", "G", "E", "A"])); // ["Dm7", "G7", "E7", "A7"]
console.log(jazzify(["F7", "E7", "A7", "Ab7", "Gm7", "C7"])); // ["F7", "E7", "A7", "Ab7", "Gm7", "C7"]
console.log(jazzify([])); // []

function mean(num) {
  let digits = num.toString().split('');
  let sum = 0;

  for(let i = 0; i < digits.length; i++) {
    sum += parseInt(digits[i]);
  }

  return Math.floor(sum / digits.length);
}

console.log(mean(42)); // 3
console.log(mean(12345)); // 3
console.log(mean(666)); // 6

function uniqueSort(arr) {
  let uniqueArray = [];

  for(let i = 0; i < arr.length; i++) {
    if(uniqueArray.indexOf(arr[i]) === -1) {
      uniqueArray.push(arr[i]);
    }
  }

  uniqueArray.sort(function(a, b) {
    return a - b;
  });

  return uniqueArray;
}

console.log(uniqueSort([1, 2, 4, 3])); // [1, 2, 3, 4]
console.log(uniqueSort([1, 4, 4, 4, 4, 4, 3, 2, 1, 2])); // [1, 2, 3, 4]
console.log(uniqueSort([6, 7, 3, 2, 1])); // [1, 2, 3, 6, 7]

function diceGame(matrix) {
  let score = 0;

  for(let i = 0; i < matrix.length; i++) {
    let dice1 = matrix[i][0];
    let dice2 = matrix[i][1];

    if(dice1 === dice2) {
      return 0;
    }

    score += dice1 + dice2;
  }

  return score;
}

console.log(diceGame([[1, 2], [3, 4], [5, 6]])); // 21
console.log(diceGame([[1, 1], [5, 6], [6, 4]])); // 0
console.log(diceGame([[4, 5], [4, 5], [4, 5]])); // 27

function rps(p1, p2) {
  if(p1 === p2) {
    return "It's a draw";
  } 

  if(
    (p1 === "Rock" && p2 === "Scissors") ||
    (p1 === "Scissors" && p2 === "Paper") ||
    (p1 === "Paper" && p2 === "Rock")
  ) {
    return "The winner is p1";
  } else {
    return "The winner is p2";
  }
}

console.log(rps("Rock", "Paper")); // "The winner is p2"
console.log(rps("Scissors", "Paper")); // "The winner is p1"
console.log(rps("Paper", "Paper")); // "It's a draw"

function matrix(x, y, z) {
  let subarrays = [];

  for(let i = 0; i < x; i++) {
    let subarray = [];

    for(let j = 0; j < y; j++) {
      subarray.push(z);
    }

    subarrays.push(subarray);
  }

  return subarrays;
}

console.log(matrix(3, 2, 3)); // [[3, 3], [3, 3], [3, 3]]
console.log(matrix(2, 1, "edabit")); // [["edabit"], ["edabit"]]
console.log(matrix(3, 2, 0)); // [[0, 0], [0, 0], [0, 0]]
